import React, { useEffect, useState } from 'react';

const CLIENT_ID = 'YOUR_CLIENT_ID';
const REDIRECT_URI = 'YOUR_REDIRECT_URI';
const AUTH_URL = 'https://authorization-server.com/auth';
const SCOPES = 'your_scopes';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      const token = new URLSearchParams(hash.replace('#', '?')).get('access_token');
      if (token) {
        setAccessToken(token);
        // Optionally store token securely (e.g., in memory)
      }
    }
  }, []);

  const handleLogin = () => {
    const url = `${AUTH_URL}?response_type=token&client_id=${encodeURIComponent(CLIENT_ID)}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&scope=${encodeURIComponent(SCOPES)}`;
    window.location.href = url;
  };

  const handleLogout = () => {
    setAccessToken(null);
    // Optionally clear token from memory
  };

  return (
    <div>
      <h1>OAuth 2.0 Implicit Flow Example</h1>
      {accessToken ? (
        <div>
          <h2>Welcome!</h2>
          <button onClick={handleLogout}>Logout</button>
        </div>
      ) : (
        <button onClick={handleLogin}>Login</button>
      )}
    </div>
  );
};

export default App;